import os
import re

# Find all files with the new name
new_name = r'\bdispatch_array_function\b'
files_with_changes = {}

for root, dirs, files in os.walk('/workspace'):
    dirs[:] = [d for d in dirs if d not in ['.git', '__pycache__', '.pytest_cache', 'build', 'dist']]

    for file in files:
        if not file.endswith('.py'):
            continue

        filepath = os.path.join(root, file)

        try:
            with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
                content = f.read()
                matches = len(re.findall(new_name, content))

                if matches > 0:
                    # Make path relative for readability
                    rel_path = filepath.replace('/workspace/', '')
                    files_with_changes[rel_path] = matches
        except:
            pass

print("=== Files updated by refactoring ===\n")
print(f"Total files changed: {len(files_with_changes)}\n")

# Group by directory
by_dir = {}
for filepath, count in sorted(files_with_changes.items()):
    dir_name = os.path.dirname(filepath)
    if dir_name not in by_dir:
        by_dir[dir_name] = []
    by_dir[dir_name].append((os.path.basename(filepath), count))

for dir_name in sorted(by_dir.keys()):
    print(f"\n{dir_name}/")
    for filename, count in sorted(by_dir[dir_name]):
        print(f"  {filename}: {count} occurrences")
